using System.Text.RegularExpressions;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "-1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsSeparator()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, ") ");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("2125551234");

        Assert.AreEqual("(212) 555-1234", result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void FormatPhoneNumber_NullInput_Throws()
    {
        _formatter.FormatPhoneNumber(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void FormatPhoneNumber_WrongLength_Throws()
    {
        _formatter.FormatPhoneNumber("123");
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_WithName_StartsWithDear()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_ContainsMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Mr.");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
        StringAssert.EndsWith(result, "Johnson,");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void BuildGreeting_WhitespaceName_Throws()
    {
        _formatter.BuildGreeting("   ");
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("My Article! #1");

        StringAssert.Matches(result, new Regex(@"^[a-z0-9\-]+$"));
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithLetters_StartsWithLowercase()
    {
        var result = _formatter.GenerateSlug("Best Practices for C#");

        StringAssert.StartsWith(result, "best");
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartOrEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("--Hello World--");

        Assert.IsFalse(result.StartsWith('-'));
        Assert.IsFalse(result.EndsWith('-'));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GenerateSlug_WhitespaceInput_Throws()
    {
        _formatter.GenerateSlug("   ");
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_WithDefaultSymbol_StartsWithDollar()
    {
        var result = _formatter.FormatCurrency(19.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_WithCustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(9.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(100m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        StringAssert.Contains(result, "-");
        StringAssert.EndsWith(result, "5.50");
    }
}

